from vex import VerificationResult
from haystack import component

@component
class VexVerifier:
    def __init__(self, verifier: Verifier):
        self.verifier = verifier

    @component.input_types(raw_extraction=dict, documents=list)
    @component.output_types(
        verified_extraction=dict,
        score=float,
        passed=bool,
        issues=list
    )
    def run(self, raw_extraction: dict, documents: list) -> dict:
        result = self.verifier.verify(
            data=raw_extraction,
            context=[doc.content for doc in documents]
        )
        return {
            'verified_extraction': result.data,
            'score': result.score,
            'passed': result.passed,
            'issues': result.issues
        }

vex_verifier = VexVerifier(verifier=verifier)

pipeline.add_component('vex_verifier', vex_verifier)
pipeline.connect('generator.documents', 'vex_verifier.documents')
pipeline.connect('parser.extracted_invoice', 'vex_verifier.raw_extraction')

result = pipeline.run({
    'retrieval': {'query': 'invoice INV-123456'},
    'prompt_builder': {'schema_json': Invoice.model_json_schema()}
})

if result['vex_verifier']['passed']:
    final_invoice = result['vex_verifier']['verified_extraction']
    print('✅ Verified extraction:', final_invoice)
else:
    print('❌ Issues:', result['vex_verifier']['issues'])
